/**
 * Creates the Quantum Literal.
 */
export function createQuantumLiteral(basis: QuantumBasis): QuantumLiteral {
  switch (basis) {
    case '1':
      return {
        kind: 'qubit',
        basis,
        alpha: 0,
        beta: 1,
        dimension: APPLICATION_DIMENSION,
        currentDimension: 'quantum',
      };
    case '+':
      return {
        kind: 'qubit',
        basis,
        alpha: Math.SQRT1_2,
        beta: Math.SQRT1_2,
        dimension: APPLICATION_DIMENSION,
        currentDimension: 'quantum',
      };
    case '-':
      return {
        kind: 'qubit',
        basis,
        alpha: Math.SQRT1_2,
        beta: -Math.SQRT1_2,
        dimension: APPLICATION_DIMENSION,
        currentDimension: 'quantum',
      };
    case '0':
    default:
      return {
        kind: 'qubit',
        basis: '0',
        alpha: 1,
        beta: 0,
        dimension: APPLICATION_DIMENSION,
        currentDimension: 'quantum',
      };
  }
}

export const QUANTUM_LITERALS = {
  ZERO: createQuantumLiteral('0'),
  ONE: createQuantumLiteral('1'),
  PLUS: createQuantumLiteral('+'),
  MINUS: createQuantumLiteral('-'),
  BELL: {
    kind: 'register',
    name: 'bell',
    qubits: [createQuantumLiteral('+'), createQuantumLiteral('0')],
    entangled: true,
    dimension: APPLICATION_DIMENSION,
    currentDimension: 'quantum',
  } satisfies QuantumRegisterLiteral,
} as const;

